// GUARDiAN GATE — idempotency hash + field/risk validation.
// Output: decision + guardian{status,reason,risk_score} + execution_hash.
const raw = $input.first().json;
const d = raw.body || raw;
function hash(str){let h=5381;for(let i=0;i<str.length;i++){h=((h<<5)+h)+str.charCodeAt(i);h=h&0xffffffff;}return 'exh_'+(h>>>0).toString(16);}
const required = ['decision_id','domain','recommended_action','routing'];
const missing = required.filter(k => d[k] == null);
const systems = (d.routing && d.routing.systems) || [];
const execution_hash = hash(JSON.stringify({ id: d.decision_id, sys: systems, action: d.recommended_action }));
let status='approved', reason='passed guardian checks', risk=0.2;
if (missing.length) { status='rejected'; reason='missing fields: '+missing.join(', '); risk=1.0; }
else if (String(d.domain).toLowerCase() !== 'property') { status='rejected'; reason='Execution Fabric v1 is Property-only'; risk=0.9; }
else if (/financial|pricing|rent|fee/i.test(d.recommended_action)) { status='requires_review'; reason='financial change requires human approval'; risk=0.7; }
// NOTE: real idempotency dedupe should look up execution_hash in a persistent store
// (Notion/Redis) and set status='rejected' (duplicate) if already executed.
return [{ json: { ...d, guardian: { status, reason, risk_score: risk }, execution_hash } }];

// EXECUTE PROPERTY ACTIONS — routes the decision to system actions.
// v1: SIMULATED success. Replace each block with a real HTTP Request / Notion
// node when Yardi (Voyager API) + CRM IQ (fresh loginguid) access is available.
const d = $input.first().json;
const action = String(d.recommended_action || '').toLowerCase();
const executed = [];

// Maintenance acceleration → Yardi work orders
// REAL: POST {yardi}/workorders/create  { priority, unit, category, notes }
if (/maintenance|backlog/.test(action)) {
  executed.push({ system:'Yardi', action:'reprioritize_work_orders', payload:{ priority:'high', category:'turnover acceleration', notes:'AI PMO decision '+d.decision_id }, result:'success' });
}
// Leasing acceleration → CRM IQ tasks
// REAL: POST {crmiq}/tasks  { type:'leasing_follow_up', cadence:'increased' }
if (/leasing|outreach|tour/.test(action)) {
  executed.push({ system:'CRM_IQ', action:'create_task_batch', payload:{ type:'leasing_follow_up', cadence:'increased', notes:'AI PMO decision '+d.decision_id }, result:'success' });
}
// Vacancy / unit readiness → Yardi unit status
if (/occupancy|vacancy|readiness|turnover/.test(action)) {
  executed.push({ system:'Yardi', action:'update_unit_readiness', payload:{ notes:'AI PMO decision '+d.decision_id }, result:'success' });
}
if (!executed.length) executed.push({ system:'none', action:'noop', result:'no_matching_route' });

// Notion audit record (persisted downstream by the 'Save Audit — Executed' Notion node)
const audit = {
  decision_id: d.decision_id,
  actions: executed,
  systems: [...new Set(executed.map(e => e.system))],
  execution_hash: d.execution_hash,
  timestamp: new Date().toISOString()
};
return [{ json: { ...d, executed, audit } }];

// EXECUTION VERIFICATION — confirm each action landed.
const d = $input.first().json;
const acts = d.executed || [];
const verified = acts.filter(e => e.result === 'success');
const failed = acts.filter(e => e.result !== 'success' && e.system !== 'none');
let execution_status = 'success';
if (failed.length && verified.length) execution_status = 'partial';
else if (!verified.length) execution_status = 'failed';
return [{ json: { ...d, verification: { execution_status, verified_actions: verified.map(v => v.system+':'+v.action), failed_actions: failed.map(f => f.system+':'+f.action) } } }];

// CIRO FEEDBACK — the record that feeds the Outcome Attribution layer.
const d = $input.first().json;
const feedback = {
  decision_id: d.decision_id,
  domain: d.domain,
  execution_result: d.verification.execution_status,
  systems_updated: d.verification.verified_actions,
  execution_hash: d.execution_hash,
  guardian: d.guardian,
  audit: d.audit,
  timestamp: new Date().toISOString(),
  status: d.verification.execution_status === 'success' ? 'verified' : 'review'
};
return [{ json: feedback }];

// Blocked by GUARDiAN — return the rejection reason (no execution).
const d = $input.first().json;
return [{ json: { decision_id: d.decision_id, domain: d.domain, status: 'blocked', guardian: d.guardian, execution_hash: d.execution_hash, timestamp: new Date().toISOString() } }];
